// Define the CSR address of xdma, should be generated by scala
#include "snax_xdma_addr.h"
// BINGO_TRACE_* markers used by xdma_layout_run (already pulled by snrt.h before this
// header; included explicitly so the layout helpers below are self-contained).
#include "perf_tracing.h"
// #define XDMA_DEBUG
#ifdef XDMA_DEBUG
#define XDMA_DEBUG_PRINT(...) printf(__VA_ARGS__)
#else
#define XDMA_DEBUG_PRINT(...)
#endif

// Define the base address of XDMA MMIO
#define SNAX_XDMA_CFG_ADDR 960
__attribute__((always_inline)) static inline uint32_t snax_read_xdma_cfg_reg(uint32_t addr) {
    return csrr_ss(SNAX_XDMA_CFG_ADDR + addr);
}

__attribute__((always_inline)) static inline void snax_write_xdma_cfg_reg(uint32_t addr, uint32_t value) {
    csrw_ss(SNAX_XDMA_CFG_ADDR + addr, value);
}

// Is `addr` inside the calling cluster's local L1 (TCDM)? The xDMA engine is
// cluster-local: it only has a port into local L1, so a plain transfer needs at
// least one endpoint here. Uses the low-32 bits (cross-chiplet high-32
// addressing is out of scope). snrt_l1_start_addr / snrt_l1_end_addr
// (occamy_memory.h) are visible here via snrt.h's include order.
static inline bool xdma_addr_in_local_l1(uint64_t addr) {
    uint32_t lo = (uint32_t)addr;
    return (lo >= snrt_l1_start_addr()) && (lo < snrt_l1_end_addr());
}

// Data Copy Task
inline int32_t xdma_memcpy_nd_full_addr(
    uint64_t src, uint64_t dst, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    // xDMA is cluster-local: it only has a port into the calling cluster's L1,
    // so at least one endpoint must live there. Enforced here so every memcpy
    // path (xdma_memcpy_1d_full_addr / _nd / _1d all delegate to this) is
    // covered without each caller repeating the check. Returns the error code
    // only; the caller-side wrapper (BINGO_XDMA_TRY) reports it.
    if (!xdma_addr_in_local_l1(src) && !xdma_addr_in_local_l1(dst)) {
        return -2;  // no transfer endpoint in local L1
    }
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)src);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(src >> 32));

    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB, (uint32_t)dst);
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB, (uint32_t)(dst >> 32));

    for (uint32_t i = 1; i < XDMA_MAX_DST_COUNT; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2, 0);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2, 0);
    }

    // Rule check
    // The enabled spatial bound for input should be equal to the enabled
    // Src frame count and dst frame count should be equal
    uint32_t src_size = 1;
    if (temp_dim_src > 0) {
        for (uint32_t i = 0; i < temp_dim_src; i++) {
            src_size *= temp_bound_src[i];
        }
    }
    uint32_t dst_size = 1;
    if (temp_dim_dst > 0) {
        for (uint32_t i = 0; i < temp_dim_dst; i++) {
            dst_size *= temp_bound_dst[i];
        }
    }
    if (src_size != dst_size) {
        XDMA_DEBUG_PRINT("src loop and dst loop is not equal\n");
        // return -3;
    }
    // Spatial Stride at src
    snax_write_xdma_cfg_reg(XDMA_SRC_SPATIAL_STRIDE_PTR, spatial_stride_src);

    // Spatial Stride at dst
    snax_write_xdma_cfg_reg(XDMA_DST_SPATIAL_STRIDE_PTR, spatial_stride_dst);

    // Temporal Dimension 0 to n at src
    for (uint32_t i = 0; i < temp_dim_src; i++) {
        if (i >= XDMA_SRC_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Source dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, temp_bound_src[i]);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i,
                                temp_stride_src[i]);
    }
    // Dimension n to MAX at src
    for (uint32_t i = temp_dim_src; i < XDMA_SRC_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i, 0);
    }
    // Temporal Dimension 0 to n at dst
    for (uint32_t i = 0; i < temp_dim_dst; i++) {
        if (i >= XDMA_DST_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Destination dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, temp_bound_dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i,
                                temp_stride_dst[i]);
    }
    // Dimension n to MAX at dst
    for (uint32_t i = temp_dim_dst; i < XDMA_DST_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i, 0);
    }
    // Enabled channel at src
    snax_write_xdma_cfg_reg(XDMA_SRC_ENABLED_CHAN_PTR, enabled_chan_src);
    // Enabled channel at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_CHAN_PTR, enabled_chan_dst);
    // Enabled byte at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_BYTE_PTR, enabled_byte_dst);
    return 0;
}

inline int32_t xdma_memcpy_nd(void* src, void* dst, uint32_t spatial_stride_src,
                              uint32_t spatial_stride_dst,
                              uint32_t temp_dim_src, uint32_t* temp_stride_src,
                              uint32_t* temp_bound_src, uint32_t temp_dim_dst,
                              uint32_t* temp_stride_dst,
                              uint32_t* temp_bound_dst,
                              uint32_t enabled_chan_src,
                              uint32_t enabled_chan_dst,
                              uint32_t enabled_byte_dst) {
    uint64_t cluster_base_address_h = snrt_cluster_base_addrh();
    cluster_base_address_h = cluster_base_address_h << 32;
    return xdma_memcpy_nd_full_addr(
        (uint64_t)src + cluster_base_address_h,
        (uint64_t)dst + cluster_base_address_h, spatial_stride_src,
        spatial_stride_dst, temp_dim_src, temp_stride_src, temp_bound_src,
        temp_dim_dst, temp_stride_dst, temp_bound_dst, enabled_chan_src,
        enabled_chan_dst, enabled_byte_dst);
}

// Minimal re-task of a transfer whose temporal SHAPE (dims, strides, channels) is unchanged
// from a prior memcpy_nd (config is sticky): rewrites only the src/dst base addresses and the
// dst dim-0 bound. 5 CSR writes instead of ~44. Use for successive same-shape tasks (e.g.
// softmax T2/T3 all stream `beats` src beats; only the addresses and the writer's beat count
// change). The opt-in "sticky CSR" path: the first op of a same-shape group does a full
// xdma_memcpy_nd_full_addr, the rest retask. Unicast only.
inline int32_t xdma_retask_1d(void* src, void* dst, uint32_t dst_bound0) {
    uint64_t h = (uint64_t)snrt_cluster_base_addrh() << 32;
    uint64_t s = (uint64_t)src + h;
    uint64_t d = (uint64_t)dst + h;
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)s);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(s >> 32));
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB, (uint32_t)d);
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB, (uint32_t)(d >> 32));
    snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR, dst_bound0);
    return 0;
}

inline int32_t xdma_memcpy_1d_full_addr(uint64_t src, uint64_t dst,
                                        uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        XDMA_DEBUG_PRINT("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_memcpy_nd_full_addr(
        src, dst, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
        XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride, temporal_bound, 1,
        temporal_stride, temporal_bound, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

inline int32_t xdma_memcpy_1d(void* src, void* dst, uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        XDMA_DEBUG_PRINT("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_memcpy_nd(src, dst, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
                          XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride,
                          temporal_bound, 1, temporal_stride, temporal_bound,
                          0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

// Multicast Task
inline int32_t xdma_multicast_nd_full_address(
    uint64_t src, uint64_t* dst, uint32_t dst_num, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)src);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(src >> 32));

    if (dst_num > XDMA_MAX_DST_COUNT) {
        XDMA_DEBUG_PRINT("Number of destination exceeds the hardware limit\n");
    }

    // Set the destination address for each destination
    for (uint32_t i = 0; i < dst_num; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2,
                                (uint32_t)dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2,
                                (uint32_t)(dst[i] >> 32));
    }

    // The remaining is set to 0, and XDMA will stop the chained copy to the
    // next destination
    for (uint32_t i = dst_num; i < XDMA_MAX_DST_COUNT; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2, 0);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2, 0);
    }
    // Rule check
    // The enabled spatial bound for input should be equal to the enabled
    // Src frame count and dst frame count should be equal
    uint32_t src_size = 1;
    if (temp_dim_src > 0) {
        for (uint32_t i = 0; i < temp_dim_src; i++) {
            src_size *= temp_bound_src[i];
        }
    }
    uint32_t dst_size = 1;
    if (temp_dim_dst > 0) {
        for (uint32_t i = 0; i < temp_dim_dst; i++) {
            dst_size *= temp_bound_dst[i];
        }
    }
    if (src_size != dst_size) {
        XDMA_DEBUG_PRINT("src loop and dst loop is not equal\n");
        // return -3;
    }

    // Spatial Stride at src
    snax_write_xdma_cfg_reg(XDMA_SRC_SPATIAL_STRIDE_PTR, spatial_stride_src);

    // Spatial Stride at dst
    snax_write_xdma_cfg_reg(XDMA_DST_SPATIAL_STRIDE_PTR, spatial_stride_dst);

    // Temporal Dimension 0 to n at src
    for (uint32_t i = 0; i < temp_dim_src; i++) {
        if (i >= XDMA_SRC_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Source dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, temp_bound_src[i]);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i,
                                temp_stride_src[i]);
    }
    // Dimension n to MAX at src
    for (uint32_t i = temp_dim_src; i < XDMA_SRC_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i, 0);
    }
    // Temporal Dimension 0 to n at dst
    for (uint32_t i = 0; i < temp_dim_dst; i++) {
        if (i >= XDMA_DST_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Destination dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, temp_bound_dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i,
                                temp_stride_dst[i]);
    }
    // Dimension n to MAX at dst
    for (uint32_t i = temp_dim_dst; i < XDMA_DST_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i, 0);
    }
    // Enabled channel at src
    snax_write_xdma_cfg_reg(XDMA_SRC_ENABLED_CHAN_PTR, enabled_chan_src);
    // Enabled channel at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_CHAN_PTR, enabled_chan_dst);
    // Enabled byte at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_BYTE_PTR, enabled_byte_dst);
    return 0;
}

inline int32_t xdma_multicast_nd(
    void* src, void** dst, uint32_t dst_num, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    uint64_t cluster_base_address_h = snrt_cluster_base_addrh();
    cluster_base_address_h = cluster_base_address_h << 32;

    uint64_t dst_full_address[XDMA_MAX_DST_COUNT];
    for (uint32_t i = 0; i < dst_num; i++) {
        dst_full_address[i] = (uint64_t)dst[i] + cluster_base_address_h;
    }
    for (uint32_t i = dst_num; i < XDMA_MAX_DST_COUNT; i++) {
        dst_full_address[i] = 0;
    }

    return xdma_multicast_nd_full_address(
        (uint64_t)src + cluster_base_address_h, dst_full_address, dst_num,
        spatial_stride_src, spatial_stride_dst, temp_dim_src, temp_stride_src,
        temp_bound_src, temp_dim_dst, temp_stride_dst, temp_bound_dst,
        enabled_chan_src, enabled_chan_dst, enabled_byte_dst);
}

inline int32_t xdma_multicast_1d_full_address(uint64_t src, uint64_t* dst,
                                              uint32_t dst_num, uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        printf_safe("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_multicast_nd_full_address(
        src, dst, dst_num, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
        XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride, temporal_bound, 1,
        temporal_stride, temporal_bound, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

inline int32_t xdma_multicast_1d(void* src, void** dst, uint32_t dst_num,
                                 uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        printf_safe("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_multicast_nd(src, dst, dst_num, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
                             XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride,
                             temporal_bound, 1, temporal_stride, temporal_bound,
                             0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

// Extension
// xdma extension interface
//
// xdma_enable_{src,dst}_ext take an extension index and its parameter CSR values and program the
// extension. The per-extension CSR layout comes from the generated header: XDMA_{SRC,DST}_EXT_NUM
// extensions, with the XDMA_{SRC,DST}_EXT_CUSTOM_CSR_NUM list giving each extension's CSR count. An
// extension's parameter CSRs occupy a contiguous slot range that starts at the prefix sum of the
// preceding extensions' counts.
//
// Each parameter CSR is written through xdma_{src,dst}_ext_csr_write(slot, val): a switch(slot) whose
// arms each write to a compile-time-constant CSR address (base + slot), so snax_write_xdma_cfg_reg /
// csrw_ss resolves to a single csrw. The switches cover a fixed slot cap; the _Static_assert checks
// the generated total CSR count stays within that cap.
#define BINGO_XDMA_EXT_CSR_CASE(base, k) \
    case (k): snax_write_xdma_cfg_reg((base) + (k), val); break

static inline void xdma_src_ext_csr_write(uint32_t slot, uint32_t val) {
    _Static_assert(XDMA_SRC_EXT_CSR_NUM <= 16,
        "src ext CSRs exceed the 16-slot dispatch cap; extend the case list below.");
    switch (slot) {
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 0);  BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 1);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 2);  BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 3);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 4);  BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 5);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 6);  BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 7);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 8);  BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 9);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 10); BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 11);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 12); BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 13);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 14); BINGO_XDMA_EXT_CSR_CASE(XDMA_SRC_EXT_CSR_PTR, 15);
        default: break;
    }
}

static inline void xdma_dst_ext_csr_write(uint32_t slot, uint32_t val) {
    _Static_assert(XDMA_DST_EXT_CSR_NUM <= 8,
        "dst ext CSRs exceed the 8-slot dispatch cap; extend the case list below.");
    switch (slot) {
        BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 0); BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 1);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 2); BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 3);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 4); BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 5);
        BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 6); BINGO_XDMA_EXT_CSR_CASE(XDMA_DST_EXT_CSR_PTR, 7);
        default: break;
    }
}
#undef BINGO_XDMA_EXT_CSR_CASE

inline int32_t xdma_enable_src_ext(uint8_t ext, uint32_t* csr_value) {
    if (ext >= XDMA_SRC_EXT_NUM) {
        return -1;
    }
    // Set the extension's enable bit.
    snax_write_xdma_cfg_reg(
        XDMA_SRC_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_SRC_ENABLE_PTR) | (1 << ext));
    // Write ext's parameter CSRs; its first slot is the prefix sum of the preceding extensions' counts.
    const uint8_t counts[XDMA_SRC_EXT_NUM] = XDMA_SRC_EXT_CUSTOM_CSR_NUM;
    uint32_t slot = 0;
    for (uint8_t e = 0; e < ext; e++) slot += counts[e];
    for (uint8_t i = 0; i < counts[ext]; i++) xdma_src_ext_csr_write(slot + i, csr_value[i]);
    return 0;
}

inline int32_t xdma_enable_dst_ext(uint8_t ext, uint32_t* csr_value) {
    if (ext >= XDMA_DST_EXT_NUM) {
        return -1;
    }
    snax_write_xdma_cfg_reg(
        XDMA_DST_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_DST_ENABLE_PTR) | (1 << ext));
    const uint8_t counts[XDMA_DST_EXT_NUM] = XDMA_DST_EXT_CUSTOM_CSR_NUM;
    uint32_t slot = 0;
    for (uint8_t e = 0; e < ext; e++) slot += counts[e];
    for (uint8_t i = 0; i < counts[ext]; i++) xdma_dst_ext_csr_write(slot + i, csr_value[i]);
    return 0;
}

inline int32_t xdma_disable_src_ext(uint8_t ext) {
    if (ext >= XDMA_SRC_EXT_NUM) {
        return 0;
    }
    snax_write_xdma_cfg_reg(
        XDMA_SRC_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_SRC_ENABLE_PTR) & ~(1 << ext));
    return 0;
}

inline int32_t xdma_disable_dst_ext(uint8_t ext) {
    if (ext >= XDMA_DST_EXT_NUM) {
        return 0;
    }
    snax_write_xdma_cfg_reg(
        XDMA_DST_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_DST_ENABLE_PTR) & ~(1 << ext));
    return 0;
}

// Handle for one issued xDMA transfer. `task_id` is the value the committed finish counter
// must reach; `remote` records WHICH counter the HW bumped (0 = LOCAL, 1 = REMOTE). The xDMA
// HW decides local vs remote from the transfer's writer/dst path; xdma_start() observes which
// COMMIT counter it bumped and returns it here, so xdma_wait_task() polls the MATCHING finish
// counter instead of guessing from the (ambiguous) src/dst addresses. Carrying the bit in the
// returned handle keeps the provenance per-transfer -- no shared global, no dependence on
// start/wait being called back-to-back, and reentrant across in-flight transfers.
typedef struct {
    uint32_t task_id;
    uint8_t remote;
} xdma_task_t;

// Start
inline xdma_task_t xdma_start() {
    int local_task_id = snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR);
    int remote_task_id = snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR);
    snax_write_xdma_cfg_reg(XDMA_START_PTR, 1);
    while (1) {
        // Wait for xdma to start
        if (snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR) !=
            local_task_id) {
            // HW committed a LOCAL task
            return (xdma_task_t){
                snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR), 0};
        }
        if (snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR) !=
            remote_task_id) {
            // HW committed a REMOTE task
            return (xdma_task_t){
                snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR), 1};
        }
    }
}

// Wait xdma to finished
inline void xdma_local_wait(uint32_t task_id) {
    while (snax_read_xdma_cfg_reg(XDMA_FINISH_LOCAL_TASK_PTR) < task_id) {
        // Wait for xdma to finish
    }
}

inline void xdma_remote_wait(uint32_t task_id) {
    while (snax_read_xdma_cfg_reg(XDMA_FINISH_REMOTE_TASK_PTR) < task_id) {
        // Wait for xdma to finish
    }
}

// Wait for xdma task completion. The xDMA HW routes each transfer to EITHER the local or
// the remote finish counter, decided by the writer/dst datapath -- which is NOT reliably
// decodable from the src/dst addresses alone (a same-chip wide-SPM/L3 reblock and a genuine
// cross-chip transfer can look alike in the address bits, and the wide SPM is not cluster-
// partitioned). xdma_start() already recorded which COMMIT counter the HW bumped in the
// returned handle, so poll the MATCHING finish counter. The old address heuristic mis-fired
// both ways -- it waited on REMOTE for a local L3<->L3 reblock (multichip llama3 swiglu), and
// on LOCAL for a transfer the HW ran remote -- and either way the DM core spun forever on a
// counter that never advances.
inline void xdma_wait_task(xdma_task_t task) {
    if (task.remote) {
        xdma_remote_wait(task.task_id);
    } else {
        xdma_local_wait(task.task_id);
    }
}

// Disable all xDMA datapath extensions (reader + writer).
// Must be called before any xDMA transfer to ensure clean state.
inline void xdma_disable_all_extensions() {
    for (uint8_t i = 0; i < XDMA_SRC_EXT_NUM; i++) {
        xdma_disable_src_ext(i);
    }
    for (uint8_t i = 0; i < XDMA_DST_EXT_NUM; i++) {
        xdma_disable_dst_ext(i);
    }
}

inline uint32_t xdma_last_task_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_TASK);
}

inline uint32_t xdma_last_read_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_READER);
}

inline uint32_t xdma_last_write_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_WRITER);
}

// ============================================================================
// Layout-convert staging helper
// ============================================================================
// xDMA's reader is tied to the calling cluster's L1 TCDM, so the src of a
// layout-convert transfer must live in local L1. The writer, on the other
// hand, can target any address in the global space — so dst can be L3 or a
// remote cluster's L1 directly (no stage-out needed; xDMA performs the layout
// transform during the write).
//
// This helper:
//   1. If `src` already points inside the calling cluster's local L1, uses it
//      as-is (zero-copy fast path).
//   2. Otherwise allocates an L1 scratch buffer, IDMA-copies `bytes` of src
//      data into it, and returns the staged L1 address as `xdma_src`. The
//      caller should free it via `xdma_layout_stage_free` after xDMA finishes.
//
// Depends on runtime symbols that must already be visible at the include
// site: snrt_l1_start_addr / snrt_l1_end_addr (occamy_memory.h),
// snrt_l1_malloc / snrt_l1_free (snrt_l1_alloc.h), chiplet_addr_transform
// (chip_id.h), snrt_dma_start_1d_wideptr / snrt_dma_wait_all (snitch DMA).
typedef struct {
    uint64_t xdma_src;       // src address to pass to xDMA (always local L1)
    uint32_t stage_in_lo;    // L1 scratch ptr to free, or 0 for fast path
} xdma_layout_stage_t;

static inline int xdma_layout_stage_in(
    xdma_layout_stage_t *s, uint64_t src, uint32_t bytes)
{
    bool src_local = xdma_addr_in_local_l1(src);

    s->stage_in_lo = 0;
    if (src_local) {
        s->xdma_src = src;
        return 0;
    }
    s->stage_in_lo = snrt_l1_malloc(bytes);
    if (!s->stage_in_lo) {
        return -1;
    }
    snrt_dma_start_1d_wideptr(
        chiplet_addr_transform((uint64_t)s->stage_in_lo),
        src, bytes);
    snrt_dma_wait_all();
    s->xdma_src = chiplet_addr_transform((uint64_t)s->stage_in_lo);
    return 0;
}

static inline void xdma_layout_stage_free(xdma_layout_stage_t *s) {
    if (s->stage_in_lo) {
        snrt_l1_free(s->stage_in_lo);
        s->stage_in_lo = 0;
    }
}

// ── Out-side staging for CPU-loop layout converts ─────────────────────────
typedef struct {
    uint32_t l1;          // L1 address the CPU loop writes (dst itself, or scratch)
    uint32_t scratch_lo;  // L1 scratch to DMA out + free in _flush, or 0 if zero-copy
} xdma_layout_stage_out_t;

// Returns 0 with s->l1 set to a CPU-writable local-L1 address, or -1 on L1 alloc
// failure (nothing to free in that case). Pair a successful call with
// xdma_layout_stage_out_flush.
static inline int xdma_layout_stage_out(
    xdma_layout_stage_out_t *s, uint64_t dst, uint32_t bytes)
{
    if (xdma_addr_in_local_l1(dst)) {        // zero-copy: write straight to dst
        s->scratch_lo = 0;
        s->l1 = (uint32_t)dst;
        return 0;
    }
    s->scratch_lo = snrt_l1_malloc(bytes);   // non-local: write a scratch, flush later
    if (!s->scratch_lo) return -1;
    s->l1 = s->scratch_lo;
    return 0;
}

// Single teardown for a CPU-loop layout convert: DMA the staged dst scratch out
// to its real dst (no-op when zero-copy), wait for completion, then free BOTH
// the dst scratch and the src staging buffer. One call after the loop — does the
// transfer, the flush, and the free together. Pass the same dst/bytes given to
// xdma_layout_stage_out. (The dst L1 buffer must be allocated by
// xdma_layout_stage_out *before* the loop, since the loop writes it, so the
// alloc stays separate; only the teardown is combined here.)
static inline void xdma_layout_stage_out_flush(
    xdma_layout_stage_t *si, xdma_layout_stage_out_t *so,
    uint64_t dst, uint32_t bytes)
{
    if (so->scratch_lo) {
        snrt_dma_start_1d_wideptr(
            dst, chiplet_addr_transform((uint64_t)so->scratch_lo), bytes);
        snrt_dma_wait_all();
        snrt_l1_free(so->scratch_lo);
        so->scratch_lo = 0;
    }
    xdma_layout_stage_free(si);   // release the src staging buffer too
}

// ==========================================================================
// Generic xDMA orchestration helpers (promoted from the bingo offload kernels).
// These carry no bingo-framework dependency -- they touch only the primitives
// above + the vendor CSR map -- so they live here for reuse across apps. The
// return convention is the lib's native int32_t 0 = OK / negative = error.
// ==========================================================================

// Constant-address ("unrolled") twin of xdma_memcpy_nd_full_addr: the dst[1..15]
// multicast-slot zeroing and the 5 src/5 dst temporal dims are emitted to CONSTANT
// CSR addresses so the compiler folds each csrw to a direct write (no address
// computation, no jump-table dispatch). 2- or 3-element caller arrays are safe: the
// (K < n) ternary short-circuits the out-of-range index to the {bound 1, stride 0} fill.
_Static_assert(XDMA_MAX_DST_COUNT == 16,
    "xdma_memcpy_nd_unrolled hardcodes the dst-multicast zeroing to slots 1..15; "
    "regenerate the unroll if XDMA_MAX_DST_COUNT changes.");
static inline int32_t xdma_memcpy_nd_unrolled(
    uint64_t src, uint64_t dst, uint32_t sp_src, uint32_t sp_dst,
    uint32_t nsrc, const uint32_t *sstr, const uint32_t *sbnd,
    uint32_t ndst, const uint32_t *dstr, const uint32_t *dbnd,
    uint32_t en_chan_src, uint32_t en_chan_dst, uint32_t en_byte_dst)
{
    if (!xdma_addr_in_local_l1(src) && !xdma_addr_in_local_l1(dst)) return -2;
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)src);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(src >> 32));
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB, (uint32_t)dst);
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB, (uint32_t)(dst >> 32));
    // dst[1..15] multicast-slot zeroing, unrolled to constant addresses. These ops are
    // unicast, but zero the slots (matches the lib) so a stale addr can't be multicast to.
#define XSM_ZDST(K) do { snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + (K) * 2, 0); \
                         snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + (K) * 2, 0); } while (0)
    XSM_ZDST(1);  XSM_ZDST(2);  XSM_ZDST(3);  XSM_ZDST(4);  XSM_ZDST(5);
    XSM_ZDST(6);  XSM_ZDST(7);  XSM_ZDST(8);  XSM_ZDST(9);  XSM_ZDST(10);
    XSM_ZDST(11); XSM_ZDST(12); XSM_ZDST(13); XSM_ZDST(14); XSM_ZDST(15);
#undef XSM_ZDST
    snax_write_xdma_cfg_reg(XDMA_SRC_SPATIAL_STRIDE_PTR, sp_src);
    snax_write_xdma_cfg_reg(XDMA_DST_SPATIAL_STRIDE_PTR, sp_dst);
    // 5 src + 5 dst temporal dims, constant addresses; value = the active dim, or the
    // {bound=1, stride=0} fill. The ?: short-circuits, so sstr[K]/sbnd[K] is read only
    // when K < nsrc -- a 2- or 3-element caller array is never indexed out of range.
#define XSM_SRC(K) do { \
    snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR  + (K), ((uint32_t)(K) < nsrc) ? sbnd[K] : 1u); \
    snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + (K), ((uint32_t)(K) < nsrc) ? sstr[K] : 0u); } while (0)
    XSM_SRC(0); XSM_SRC(1); XSM_SRC(2); XSM_SRC(3); XSM_SRC(4);
#undef XSM_SRC
#define XSM_DST(K) do { \
    snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR  + (K), ((uint32_t)(K) < ndst) ? dbnd[K] : 1u); \
    snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + (K), ((uint32_t)(K) < ndst) ? dstr[K] : 0u); } while (0)
    XSM_DST(0); XSM_DST(1); XSM_DST(2); XSM_DST(3); XSM_DST(4);
#undef XSM_DST
    snax_write_xdma_cfg_reg(XDMA_SRC_ENABLED_CHAN_PTR, en_chan_src);
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_CHAN_PTR, en_chan_dst);
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_BYTE_PTR, en_byte_dst);
    return 0;
}

// Generic [M,N] -> [N,M] element transpose on the DM core (any elem_bytes). Non-local
// operands are staged through L1 via the xdma_layout_stage_* helpers above (the DM core
// is not L3-coherent). Returns 0 on success, -1 if L1 staging fails.
static inline int32_t xdma_cpu_transpose_2d(uint64_t src_addr, uint64_t dst_addr,
                                            uint32_t M, uint32_t N, uint32_t elem_bytes)
{
    uint32_t bytes = M * N * elem_bytes;
    xdma_layout_stage_t si;
    xdma_layout_stage_out_t so;
    if (xdma_layout_stage_in(&si, src_addr, bytes) != 0 ||
        xdma_layout_stage_out(&so, dst_addr, bytes) != 0) {
        xdma_layout_stage_free(&si);   // frees src scratch if staged; no-op otherwise
        return -1;
    }
    volatile uint8_t *src = (volatile uint8_t *)(uint32_t)si.xdma_src;
    volatile uint8_t *dst = (volatile uint8_t *)so.l1;
    for (uint32_t r = 0; r < M; r++)
        for (uint32_t c = 0; c < N; c++)
            for (uint32_t b = 0; b < elem_bytes; b++)
                dst[(c * M + r) * elem_bytes + b] = src[(r * N + c) * elem_bytes + b];
    xdma_layout_stage_out_flush(&si, &so, dst_addr, bytes);   // transfer + flush + free both
    return 0;
}

// Dispatch helper for the layout-convert HW paths: configures an AGU-only or
// AGU+Transposer xDMA transfer with the given strides/bounds, kicks it, and waits for
// completion. Keeps the per-path bodies short.
static inline void xdma_layout_run(
    uint64_t src, uint64_t dst,
    uint32_t spatial_stride_src, uint32_t spatial_stride_dst,
    uint32_t ndims,
    uint32_t *t_strides_src, uint32_t *t_bounds_src,
    uint32_t *t_strides_dst, uint32_t *t_bounds_dst,
    bool use_transposer)
{
    BINGO_TRACE_MARKER(BINGO_TRACE_XDMA_CFG_START);
    xdma_disable_all_extensions();
#ifdef WRITER_EXT_TRANSPOSERROW8_8COL8_8BIT8_16
    uint32_t tp_csr[1] = {0};  // 8x8-byte (8-bit) transpose mode
    if (use_transposer)
        xdma_enable_dst_ext(WRITER_EXT_TRANSPOSERROW8_8COL8_8BIT8_16, tp_csr);
#else
    (void)use_transposer;
#endif
    xdma_memcpy_nd_full_addr(
        src, dst,
        spatial_stride_src, spatial_stride_dst,
        ndims, t_strides_src, t_bounds_src,
        ndims, t_strides_dst, t_bounds_dst,
        0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
    BINGO_TRACE_MARKER(BINGO_TRACE_XDMA_CFG_END);

    BINGO_TRACE_MARKER(BINGO_TRACE_XDMA_RUN_START);
    xdma_task_t task_id = xdma_start();
    xdma_wait_task(task_id);
    BINGO_TRACE_MARKER(BINGO_TRACE_XDMA_RUN_END);

#ifdef WRITER_EXT_TRANSPOSERROW8_8COL8_8BIT8_16
    if (use_transposer) xdma_disable_dst_ext(WRITER_EXT_TRANSPOSERROW8_8COL8_8BIT8_16);
#endif
}
